import{_ as t,o as e,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const M=JSON.parse('{"title":"F14: 負債結構與償債壓力測試 — 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/1727_中華化/20260430/F14_負債結構與償債壓力測試_投資研究員.md","filePath":"審計報告庫/財務審計/1727_中華化/20260430/F14_負債結構與償債壓力測試_投資研究員.md"}'),o={name:"審計報告庫/財務審計/1727_中華化/20260430/F14_負債結構與償債壓力測試_投資研究員.md"};function l(n,a,s,h,c,d){return e(),r("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f14-負債結構與償債壓力測試-—-投資研究員審計報告" tabindex="-1">F14: 負債結構與償債壓力測試 — 投資研究員審計報告 <a class="header-anchor" href="#f14-負債結構與償債壓力測試-—-投資研究員審計報告" aria-label="Permalink to &quot;F14: 負債結構與償債壓力測試 — 投資研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>負債比率與利息覆蓋倍數為何？債務到期分佈是否集中於短期？在高利率環境下的利息支出承受度為何？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：負債比率31.7%，利息保障倍數約29倍，短債佔總負債34.8%；現金對短期債務覆蓋率僅0.43倍，具備再融資壓力。</li><li><strong>風險評級</strong>：中（短期流動性缺口1.9億為主要壓力點）</li><li><strong>數據時效</strong>：根據截至2025年第四季最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>負債比率</strong>：31.7%（2024年底），2025年Q4升至40.39%，槓桿回升。</li><li><strong>利息保障倍數</strong>：2024全年約33.4倍；2025年Q4約29.3倍，保障能力充足。</li><li><strong>短債佔比</strong>：短期借款259M＋一年內到期公司債77M＝336M，佔總負債964M的34.8%。</li><li><strong>現金對短債覆蓋率</strong>：146M／336M＝0.43倍，現金缺口約190M。</li><li><strong>債務到期分佈</strong>：無一年內到期長期借款；77M為中華化一公司債（2025年10月到期，利率0%）。</li><li><strong>借款利率區間</strong>：銀行信用借款1.87%~5.44%；華南銀擔保借款固定利率。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、負債結構總覽" tabindex="-1">一、負債結構總覽 <a class="header-anchor" href="#一、負債結構總覽" aria-label="Permalink to &quot;一、負債結構總覽&quot;">​</a></h3><p>截至2024年底，資產總額3,035M仟元，負債964M仟元，權益2,072M仟元。負債比率31.7%，低於產業中位數，槓桿控制佳。</p><p>流動負債767M佔總負債79.7%，非流動196M佔20.3%。短期借款259M（銀行信用借款，利率1.87%~5.44%），一年內到期公司債77M（中華化一，0%利率），長期借款185M（華南銀擔保）。</p><h3 id="二、利息保障能力" tabindex="-1">二、利息保障能力 <a class="header-anchor" href="#二、利息保障能力" aria-label="Permalink to &quot;二、利息保障能力&quot;">​</a></h3><p>2024全年營業利益70.6M，利息支出（帳列）2.1M，保障倍數約33.4倍。2025年Q4單季營業利益-0.4M，該季保障倍數轉負。</p><p>現金流量表「支付之利息」7.7M高於損益認列2.1M，差額來自借款成本資本化8.7M，實際現金利息負擔高於帳面。</p><h3 id="三、短期流動性壓力測試" tabindex="-1">三、短期流動性壓力測試 <a class="header-anchor" href="#三、短期流動性壓力測試" aria-label="Permalink to &quot;三、短期流動性壓力測試&quot;">​</a></h3><p>現金146M vs. 短期債務336M（含短借259M＋到期公司債77M），覆蓋率僅0.43倍，缺口約190M。</p><p>2025年Q4單季淨利僅1.5M，現金流不足以覆蓋短期債務。中華化一（17271）轉換公司債於2025年10月到期，若未轉換或賣回，將形成190M現金流出缺口。</p><h3 id="四、利率上升壓力模擬" tabindex="-1">四、利率上升壓力模擬 <a class="header-anchor" href="#四、利率上升壓力模擬" aria-label="Permalink to &quot;四、利率上升壓力模擬&quot;">​</a></h3><p>若利率升100點，以短借259M＋長借185M合計444M計，額外利息約4.4M／年。以2024全年稅前淨利75M計，EPS稀釋約0.04元。對當前獲利影響可控，但若營運持續低迷，利息負擔將侵蝕微薄利潤。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：再融資風險集中於2025年Q4</strong>。中華化一（17271）轉換公司債76.8M於2025年10月到期，若股價未達轉換價格（已調降至29.20元）或投資人選擇賣回，將產生190M現金缺口。公司現金僅145M，需依賴新債發行或銀行授信填補。公司已申報第二次無擔保轉換公司債（中華化二，17272），YTP區間0%~0.5%，但資本市場波動下募集時程延後，再融資窗口收窄。</li><li><strong>空頭風險二：營運獲利不穩定放大利息負擔敏感度</strong>。2025年Q1~Q4營業利益連續四季為負（-8.1M、7.8M、1.7M、-0.4M），全年營業利益僅9,752仟元。若利率上升100點，額外4.4M利息將侵蝕全年營業利益近50%。在高息環境下，公司財務彈性極低，任何營運下滑都可能觸發流動性危機。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK — <code>TaiwanStockFinancialStatements</code>，stock_id=1727, 2023-01-01至2026-04-30，提取Revenue、OperatingIncome、IncomeAfterTaxes等季報數據。</li><li><strong>年報PDF</strong>: OK — 2024_Q4_1727_合併.pdf（民國113年度），提取合併資產負債表、綜合損益表、財務報告附註（借款明細、利息支出）。</li><li><strong>網路搜尋</strong>: OK — Goodinfo.tw負債比率與利息保障倍數；公司債資訊（中華化一17271、中華化二17272）。</li><li><strong>關鍵核對碼</strong>：2024年底負債比率=963,505/3,035,379=31.74%；利息保障倍數=70,569/2,115=33.4x；現金對短債覆蓋率=145,528/335,855=0.43x。</li></ul>',24)])])}const u=t(o,[["render",l]]);export{M as __pageData,u as default};
